{
  "schema_version": 1,
  "request_id": "rf-suggest-edit-cross-object-citation-interleaving-001",
  "project": "radishflow",
  "task": "suggest_flowsheet_edits",
  "status": "partial",
  "requires_confirmation": true,
  "answers": [
    {
      "summary": "当前围绕已选中的进料流股 feed-31 缺少流量规格，以及已选中的分离器 separator-3 在固定压力模式下缺少操作压力目标这两类问题，生成局部候选提案；未对下游依赖流股做独立修改。",
      "issues": [
        {
          "code": "STREAM_SPEC_MISSING",
          "message": "Feed To Heater is missing flow rate specification.",
          "severity": "error",
          "target_type": "stream",
          "target_id": "feed-31",
          "citations": [
            "diag-1",
            "flowdoc-stream-1"
          ]
        },
        {
          "code": "UNIT_PARAMETER_INCOMPLETE",
          "message": "Hot Separator is configured for fixed pressure mode but the operating pressure target is missing.",
          "severity": "error",
          "target_type": "unit",
          "target_id": "separator-3",
          "citations": [
            "diag-2",
            "flowdoc-unit-2"
          ]
        }
      ],
      "proposed_actions": [
        {
          "action": "candidate_edit",
          "title": "为 feed-31 补充流量规格占位",
          "target": {
            "type": "stream",
            "id": "feed-31"
          },
          "rationale": "诊断直接指出该进料流股缺少流量规格；在仅做最小、可审查修改的前提下，补充一个流量规格占位可为求解提供必要输入，但不假定具体数值。",
          "patch": {
            "spec_placeholders": {
              "flow_rate": {
                "required": true,
                "status": "missing",
                "suggested_unit_family": "flow"
              }
            }
          },
          "risk_level": "medium",
          "requires_confirmation": true,
          "citations": [
            "diag-1",
            "flowdoc-stream-1",
            "snapshot-1"
          ]
        },
        {
          "action": "candidate_edit",
          "title": "为 separator-3 补充固定压力目标占位",
          "target": {
            "type": "unit",
            "id": "separator-3"
          },
          "rationale": "该设备已配置为 fixed pressure mode，但缺少对应操作压力目标；增加局部参数占位与当前配置一致，且避免未经证据支持地填入具体压力值。",
          "patch": {
            "parameter_placeholders": {
              "operating_pressure_kpa": {
                "required": true,
                "status": "missing"
              }
            }
          },
          "risk_level": "medium",
          "requires_confirmation": true,
          "citations": [
            "diag-2",
            "flowdoc-unit-2",
            "snapshot-1"
          ]
        }
      ],
      "confidence": 0.95,
      "citations": [
        "diag-1",
        "diag-2",
        "flowdoc-stream-1",
        "flowdoc-unit-2",
        "snapshot-1"
      ]
    }
  ]
}
